    ('seconde-maths', 'seconde', 'Mathématiques', 'Calculator', '#3B82F6', 0),
    ('seconde-physique', 'seconde', 'Physique-Chimie', 'Atom', '#EF4444', 0),
    ('seconde-anglais', 'seconde', 'Anglais', 'Languages', '#10B981', 0),
    ('seconde-francais', 'seconde', 'Français', 'BookOpen', '#F59E0B', 0)
INSERT INTO chapters (id, subject_id, level_id, number, title, description, is_completed, is_locked) VALUES
    ('seconde-maths-ch1', 'seconde-maths', 'seconde', 1, 'Ensembles de nombres et calculs', 'Introduction aux ensembles N, Z, Q, R. Opérations de base, fractions, puissances et racines carrées. Applications aux problèmes concrets du quotidien togolais.', false, false),
    ('seconde-maths-ch2', 'seconde-maths', 'seconde', 2, 'Fonctions numériques', 'Notion de fonction, ensemble de définition, représentation graphique. Fonctions affines, quadratiques et homographiques. Étude de variations et tableaux de signes.', false, false),
    ('seconde-maths-ch3', 'seconde-maths', 'seconde', 3, 'Géométrie plane', 'Points, droites, plans. Vecteurs du plan. Colinéarité, orthogonalité. Équations de droites. Distance et milieu. Applications aux problèmes de navigation et cartographie.', false, false),
    ('seconde-maths-ch4', 'seconde-maths', 'seconde', 4, 'Statistiques descriptive', 'Tableaux statistiques, graphiques (barres, secteurs, histogrammes). Indicateurs de position et de dispersion. Applications aux données démographiques et économiques du Togo.', false, false),
    ('seconde-maths-ch5', 'seconde-maths', 'seconde', 5, 'Probabilités', 'Vocabulaire des probabilités. Dénombrement, arrangements, permutations. Probabilités conditionnelles. Arbres de probabilité. Applications aux jeux de hasard et sondages.', false, false),
    ('seconde-physique-ch1', 'seconde-physique', 'seconde', 1, 'Mouvement et interactions', 'Description du mouvement : référentiel, trajectoire, vitesse. Les interactions fondamentales. Forces et équilibre. Applications aux mouvements des corps au Togo (transport, sport).', false, false),
    ('seconde-physique-ch2', 'seconde-physique', 'seconde', 2, 'Lumière et image', 'Propagation rectiligne de la lumière. Réflexion et réfraction. Lentilles convergentes. L''œil et la vision. Instruments d''optique. Applications à la photographie et la médecine.', false, false),
    ('seconde-physique-ch3', 'seconde-physique', 'seconde', 3, 'Énergie et conversions', 'Formes d''énergie : cinétique, potentielle, thermique, chimique, électrique. Transferts et conversions d''énergie. Rendement énergétique. Applications aux systèmes énergétiques togolais.', false, false),
    ('seconde-physique-ch4', 'seconde-physique', 'seconde', 4, 'Électricité', 'Courant électrique, tension, résistance. Loi d''Ohm. Circuits en série et parallèle. Puissance électrique. Sécurité électrique. Applications au réseau électrique national.', false, false),
    ('seconde-physique-ch5', 'seconde-physique', 'seconde', 5, 'Chimie de la matière', 'Classification périodique des éléments. Liaisons chimiques. Réactions acide-base, oxydoréduction. Stœchiométrie. Applications à l''agriculture et l''industrie togolaise.', false, false),
    ('seconde-anglais-ch1', 'seconde-anglais', 'seconde', 1, 'Present Tenses & Daily Routines', 'Master the present simple and present continuous. Describe daily routines, habits, and current actions. Vocabulary : time expressions, household activities, school life in Togo and abroad.', false, false),
    ('seconde-anglais-ch2', 'seconde-anglais', 'seconde', 2, 'Past Experiences & Narratives', 'Past simple and past continuous. Telling stories, describing past events. Vocabulary : travel, holidays, historical events. Reading comprehension on Togolese history in English.', false, false),
    ('seconde-anglais-ch3', 'seconde-anglais', 'seconde', 3, 'Future Plans & Predictions', 'Will, going to, present continuous for future. Making predictions, expressing intentions. Vocabulary : careers, education, technology. Debates on the future of Togo.', false, false),
    ('seconde-anglais-ch4', 'seconde-anglais', 'seconde', 4, 'Comparisons & Descriptions', 'Comparative and superlative adjectives. Describing people, places, and cultures. Vocabulary : geography, traditions, food. Comparative studies between Togolese and English-speaking cultures.', false, false),
    ('seconde-anglais-ch5', 'seconde-anglais', 'seconde', 5, 'Conditional Sentences & Wishes', 'Zero, first, and second conditionals. Expressing wishes, hypothetical situations. Vocabulary : environment, health, social issues. Role-plays and creative writing exercises.', false, false),
    ('seconde-francais-ch1', 'seconde-francais', 'seconde', 1, 'Le récit : structure et personnages', 'Analyse de la structure narrative (situation initiale, élément perturbateur, péripéties, dénouement). Les types de personnages (héros, antagoniste, figurants). Étude d''extraits de romans africains et français.', false, false),
    ('seconde-francais-ch2', 'seconde-francais', 'seconde', 2, 'La poésie : vers et figures de style', 'Le vers, la rime, le rythme. Figures de style principales : métaphore, comparaison, personnification, hyperbole. Analyse de poèmes de Senghor, Césaire, et poètes français classiques.', false, false),
    ('seconde-francais-ch3', 'seconde-francais', 'seconde', 3, 'L'argumentation : convaincre et persuader', 'Structure de l''argumentation : thèse, arguments, exemples, conclusion. Les connecteurs logiques. Techniques de persuasion. Rédaction de dissertations et commentaires d''articles de presse togolaise.', false, false),
    ('seconde-francais-ch4', 'seconde-francais', 'seconde', 4, 'Le théâtre : comédie et tragédie', 'Genres dramatiques. L''unité d''action, de lieu, de temps. Les didascalies. Analyse d''extraits de Molière, Corneille, et dramaturges africains contemporains.', false, false),
    ('seconde-francais-ch5', 'seconde-francais', 'seconde', 5, 'Grammaire : subjonctif et discours rapporté', 'Emploi du subjonctif dans les subordonnées. Concordance des temps au discours rapporté. Style direct et indirect. Exercices de transformation et réécriture.', false, false)
INSERT INTO courses (chapter_id, title, content) VALUES
    ('seconde-maths-ch1', 'Les ensembles de nombres', 'Ce cours présente les différents ensembles de nombres utilisés en mathématiques. L''ensemble des entiers naturels N = {0, 1, 2, 3, ...} sert à compter. L''ensemble des entiers relatifs Z = {..., -2, -1, 0, 1, 2, ...} ajoute les nombres négatifs. L''ensemble des rationnels Q comprend les fractions p/q où p et q sont des entiers, q ≠ 0. Enfin, l''ensemble des réels R inclut tous les nombres rationnels et irrationnels comme √2, π, e. Nous étudions les opérations de base : addition, soustraction, multiplication, division, ainsi que les propriétés commutatives, associatives et distributives. Des exemples concrets tirés de la vie quotidienne togolaise illustrent chaque concept.'),
    ('seconde-maths-ch1', 'Calculs algébriques fondamentaux', 'Ce cours approfondit les techniques de calcul algébrique indispensables pour la suite du programme. Nous apprenons à développer des expressions de la forme (a+b)² = a² + 2ab + b², (a-b)² = a² - 2ab + b², et (a+b)(a-b) = a² - b². La factorisation est ensuite étudiée : factorisation par facteur commun, par groupement, et utilisation des identités remarquables inverses. Des exercices progressifs permettent de maîtriser la simplification d''expressions fractionnaires et la résolution d''équations du premier degré à une inconnue.'),
    ('seconde-maths-ch1', 'Puissances et racines carrées', 'Ce cours traite des puissances entières positives et négatives. Pour tout nombre réel a non nul et tout entier relatif n, on définit aⁿ comme le produit de n facteurs égaux à a si n > 0, et aⁿ = 1/a⁻ⁿ si n < 0. Les règles de calcul sur les puissances sont démontrées : aᵐ × aⁿ = aᵐ⁺ⁿ, (aᵐ)ⁿ = aᵐⁿ, (ab)ⁿ = aⁿbⁿ. La racine carrée est définie comme l''opération inverse de l''élévation au carré. Nous étudions la simplification de radicaux et la rationalisation des dénominateurs.'),
    ('seconde-maths-ch2', 'Notion de fonction et ensemble de définition', 'Ce cours introduit la notion fondamentale de fonction. Une fonction f d''un ensemble E vers un ensemble F associe à chaque élément x de E au plus un élément y de F, noté f(x). L''ensemble de définition Df est l''ensemble des valeurs de x pour lesquelles f(x) existe. Nous apprenons à déterminer graphiquement et algébriquement l''ensemble de définition. Les représentations graphiques dans un repère orthonormé sont construites point par point. La notion d''image et d''antécédent est illustrée par de nombreux exemples.'),
    ('seconde-maths-ch2', 'Fonctions affines et quadratiques', 'Ce cours étudie deux familles de fonctions essentielles. Une fonction affine est de la forme f(x) = ax + b. Son graphique est une droite de coefficient directeur a et d''ordonnée à l''origine b. Nous analysons les variations selon le signe de a. Une fonction quadratique est de la forme f(x) = ax² + bx + c. Sa courbe représentative est une parabole. Nous déterminons le sommet, l''axe de symétrie, et étudions le signe du trinôme selon les valeurs du discriminant Δ = b² - 4ac.'),
    ('seconde-maths-ch2', 'Tableaux de variations et signes', 'Ce cours formalise l''étude des variations d''une fonction. Une fonction est croissante sur un intervalle I si pour tous x₁, x₂ dans I, x₁ < x₂ implique f(x₁) ≤ f(x₂). Elle est décroissante si f(x₁) ≥ f(x₂). Nous construisons des tableaux de variations à partir de la courbe représentative. Le tableau de signes d''une expression est utilisé pour résoudre des inéquations. La méthode est appliquée aux fonctions affines, quadratiques, et à des quotients d''expressions algébriques.'),
    ('seconde-maths-ch3', 'Vecteurs du plan : définition et opérations', 'Ce cours définit la notion de vecteur comme une translation du plan. Un vecteur AB est caractérisé par sa direction, son sens et sa norme. L''addition vectorielle est définie par la relation de Chasles : AB + BC = AC. La multiplication d''un vecteur par un réel k change sa norme d''un facteur |k| et inverse son sens si k < 0. Nous démontrons les propriétés algébriques de ces opérations et résolvons des problèmes géométriques par le calcul vectoriel.'),
    ('seconde-maths-ch3', 'Colinéarité et orthogonalité', 'Ce cours étudie les relations entre vecteurs. Deux vecteurs u et v sont colinéaires s''il existe un réel k tel que u = kv. Cette condition se traduit par l''annulation du déterminant det(u,v) = x_u y_v - x_v y_u = 0. Dans un repère orthonormé, deux vecteurs sont orthogonaux si leur produit scalaire u·v = x_u x_v + y_u y_v = 0. Ces critères permettent de démontrer le parallélisme et la perpendicularité de droites, ainsi que l''alignement de points.'),
    ('seconde-maths-ch3', 'Équations de droites et distances', 'Ce cours traite des différentes formes d''équations de droites. La forme réduite y = mx + p où m est le coefficient directeur et p l''ordonnée à l''origine. La forme ax + by + c = 0. L''équation de la droite passant par deux points donnés. La distance entre deux points A(x_A, y_A) et B(x_B, y_B) est donnée par AB = √((x_B-x_A)² + (y_B-y_A)²). Le milieu d''un segment a pour coordonnées ((x_A+x_B)/2, (y_A+y_B)/2). Applications aux problèmes de cartographie et de navigation côtière togolaise.'),
    ('seconde-maths-ch4', 'Tableaux et graphiques statistiques', 'Ce cours présente les méthodes de représentation des données statistiques. Les tableaux d''effectifs et de fréquences organisent les données brutes. Les diagrammes en barres comparent des effectifs entre différentes catégories. Les diagrammes circulaires (camemberts) représentent les parts d''un tout. Les histogrammes visualisent la répartition d''une variable continue en classes. Nous utilisons des données réelles sur la population, l''éducation et l''économie du Togo pour construire ces représentations.'),
    ('seconde-maths-ch4', 'Indicateurs de position', 'Ce cours définit les mesures de tendance centrale. La moyenne d''une série statistique est la somme des valeurs divisée par l''effectif total. La médiane partage la population en deux groupes de même effectif. Les quartiles Q1 et Q3 délimitent les 25% et 75% inférieurs de la population. Le mode est la valeur de plus grand effectif. Pour des données groupées en classes, nous calculons le centre de classe et la moyenne pondérée.'),
    ('seconde-maths-ch4', 'Indicateurs de dispersion', 'Ce cours mesure la variabilité d''une série statistique. L''étendue est la différence entre la valeur maximale et minimale. La variance est la moyenne des carrés des écarts à la moyenne. L''écart-type est la racine carrée de la variance. L''intervalle interquartile IQR = Q3 - Q1 mesure la dispersion centrale. Ces indicateurs permettent de comparer la régularité de différentes séries, comme les résultats scolaires entre régions du Togo ou entre matières.'),
    ('seconde-maths-ch5', 'Vocabulaire et calculs de probabilités', 'Ce cours introduit le vocabulaire des probabilités. Une expérience aléatoire est une épreuve dont le résultat dépend du hasard. L''univers Ω est l''ensemble de tous les résultats possibles. Un événement est une partie de Ω. La probabilité d''un événement A est un nombre P(A) compris entre 0 et 1. Nous calculons des probabilités dans des cas d''équiprobabilité : P(A) = nombre de cas favorables / nombre de cas possibles.'),
    ('seconde-maths-ch5', 'Dénombrement et arrangements', 'Ce cours développe les techniques de dénombrement. Le principe additif : si deux événements sont incompatibles, le nombre de cas favorables à l''un ou l''autre est la somme. Le principe multiplicatif : le nombre de façons d''effectuer deux choix successifs est le produit des possibilités. Les arrangements A(n,p) = n!/(n-p)! comptent les p-uplets ordonnés d''éléments distincts. Les permutations de n éléments sont au nombre de n!.'),
    ('seconde-maths-ch5', 'Probabilités conditionnelles et indépendance', 'Ce cours généralise le calcul des probabilités. La probabilité conditionnelle de B sachant A est P_A(B) = P(A∩B)/P(A). La formule des probabilités totales permet de décomposer un calcul complexe. Deux événements sont indépendants si P(A∩B) = P(A)×P(B). Les arbres de probabilité visualisent les situations à plusieurs étapes. Applications aux tests de dépistage médical, aux jeux de hasard, et aux sondages d''opinion.'),
    ('seconde-physique-ch1', 'Référentiels et description du mouvement', 'Ce cours définit les concepts fondamentaux de la cinématique. Un référentiel est un solide par rapport auquel on étudie le mouvement. La trajectoire est l''ensemble des positions successives occupées par un point du mobile. La vitesse moyenne est le rapport de la distance parcourue au temps écoulé. La vitesse instantanée est la dérivée de la position par rapport au temps. Nous analysons les mouvements rectilignes uniformes et uniformément variés. Des exemples concrets : le mouvement d''un zemidjan, d''un bus interurbain, d''un athlète togolais.'),
    ('seconde-physique-ch1', 'Les interactions et les forces', 'Ce cours présente les quatre interactions fondamentales de la physique : gravitationnelle, électromagnétique, forte et faible. Au niveau macroscopique, nous étudions les forces de contact (réaction normale, tension, frottement) et les forces à distance (poids, force électrostatique). La représentation d''une force se fait par un vecteur caractérisé par son point d''application, sa direction, son sens et sa norme. La condition d''équilibre d''un solide soumis à deux forces est énoncée et vérifiée expérimentalement.'),
    ('seconde-physique-ch1', 'Principe d''inertie et applications', 'Ce cours énonce le premier principe de Newton (principe d''inertie) : dans un référentiel galiléen, un corps isolé ou soumis à des forces se compensant est soit au repos, soit en mouvement rectiligne uniforme. Nous distinguons les référentiels galiléens (approximativement le référentiel terrestre pour des durées courtes) et non galiléens. Applications aux sièges de sécurité, aux appuis latéraux des virages, et à la sécurité routière au Togo.'),
    ('seconde-physique-ch2', 'Propagation et modèle de la lumière', 'Ce cours adopte le modèle du rayon lumineux. Dans un milieu homogène et transparent, la lumière se propage en ligne droite. La vitesse de la lumière dans le vide est c = 3,00×10⁸ m/s. Dans l''air, cette vitesse est légèrement inférieure. Un faisceau lumineux est un ensemble de rayons. Les objets lumineux émettent leur propre lumière (Soleil, lampe), les objets éclairés la diffusent (Lune, tableau). Nous étudions les éclipses et les phases de la Lune.'),
    ('seconde-physique-ch2', 'Réflexion et réfraction de la lumière', 'Ce cours étudie les lois de Snell-Descartes. Premier principe : les rayons incident, réfléchi et réfracté sont coplanaires avec la normale. Deuxième principe pour la réflexion : l''angle d''incidence égale l''angle de réflexion (i = r). Pour la réfraction : n₁ sin(i₁) = n₂ sin(i₂) où n est l''indice de réfraction du milieu. Le phénomène de réflexion totale est expliqué. Applications aux miroirs, fibres optiques, et instruments d''optique.'),
    ('seconde-physique-ch2', 'Lentilles convergentes et instruments d''optique', 'Ce cours décrit les lentilles minces convergentes. Le centre optique O, les foyers objet F et image F'', la distance focale f = OF''. Les trois rayons particuliers permettent de construire graphiquement l''image d''un objet. La relation de conjugaison 1/OA'' - 1/OA = 1/f'' relie positions de l''objet et de l''image. Le grandissement γ = A''B''/AB = OA''/OA. Applications à la loupe, la caméra, le projecteur, et l''œil humain.'),
    ('seconde-physique-ch3', 'Formes et transferts d''énergie', 'Ce cours inventorie les différentes formes d''énergie : cinétique (E_c = ½mv²), potentielle de pesanteur (E_p = mgh), potentielle élastique, chimique, thermique, rayonnante, nucléaire et électrique. Un transfert d''énergie modifie l''état d''un système sans changer la nature de l''énergie. Un convertisseur d''énergie transforme une forme d''énergie en une autre. Le rendement d''un convertisseur est η = E_utile / E_fournie. Nous analysons les chaînes énergétiques de différents appareils.'),
    ('seconde-physique-ch3', 'Conservation et dégradation de l''énergie', 'Ce cours énonce le principe de conservation de l''énergie : l''énergie totale d''un système isolé se conserve. Cependant, lors des conversions, une partie de l''énergie se dégrade en chaleur (pertes par effet Joule, frottement). L''efficacité énergétique devient un enjeu majeur. Nous étudions les bilans énergétiques de la combustion du bois de chauffe, du groupe électrogène, et du panneau solaire dans le contexte togolais.'),
    ('seconde-physique-ch3', 'Énergie dans les systèmes vivants', 'Ce cours applique les concepts énergétiques à la biologie. La photosynthèse convertit l''énergie lumineuse en énergie chimique (glucose). La respiration cellulaire libère cette énergie sous forme d''ATP. Les chaînes alimentaires transmettent l''énergie avec un rendement d''environ 10% par niveau trophique. L''empreinte écologique et la consommation énergétique de l''humanité sont discutées. Réflexion sur la transition énergétique au Togo.'),
    ('seconde-physique-ch4', 'Courant électrique et circuit', 'Ce cours définit le courant électrique comme un déplacement ordonné de porteurs de charge (électrons dans les métaux, ions dans les solutions). L''intensité I = Q/Δt s''exprime en ampères. Un circuit électrique est une boucle fermée comportant un générateur, des récepteurs et des fils de connexion. En série, l''intensité est la même en tout point. En dérivation, elle se divise. Nous réalisons des montages expérimentaux avec des ampèremètres et des lampes.'),
    ('seconde-physique-ch4', 'Tension et loi d''Ohm', 'Ce cours définit la tension électrique comme la différence de potentiel entre deux points d''un circuit. Elle se mesure en volts avec un voltmètre branché en parallèle. La loi d''Ohm établit que pour un conducteur ohmique, U = R×I où R est la résistance en ohms (Ω). La résistance dépend de la nature du matériau (ρ), de la longueur ℓ et de la section S par la relation R = ρℓ/S. Applications au dimensionnement des installations électriques.'),
    ('seconde-physique-ch4', 'Puissance électrique et sécurité', 'Ce cours définit la puissance électrique P = U×I = R×I² = U²/R en watts (W). L''énergie électrique consommée est E = P×t en joules ou en kWh. La facture EDM (Énergie du Togo) est décryptée. Les dangers du courant électrique dépendent de l''intensité traversant le corps. Les dispositifs de protection : fusibles, disjoncteurs différentiels, mise à la terre. Les normes de sécurité dans les bâtiments scolaires et domestiques.'),
    ('seconde-physique-ch5', 'Classification périodique des éléments', 'Ce cours présente le tableau de Mendeleïev moderne. Les éléments sont classés par numéro atomique Z croissant. Les lignes horizontales sont les périodes, les colonnes verticales les groupes. Les éléments d''un même groupe ont des propriétés chimiques similaires. Les métaux (gauche et centre) se distinguent des non-métaux (droite). Les gaz nobles (colonne 18) sont particulièrement stables. Nous localisons les éléments essentiels à l''agriculture togolaise : azote, phosphore, potassium.'),
    ('seconde-physique-ch5', 'Liaisons chimiques et molécules', 'Ce cours explique la formation des molécules. La liaison covalente résulte de la mise en commun de paires d''électrons. La liaison ionique est une attraction électrostatique entre ions de charges opposées. La représentation de Lewis montre les doublets liants et non-liants. La géométrie des molécules est prédite par le modèle VSEPR. Nous construisons des modèles de molécules simples : eau, dioxyde de carbone, ammoniac, méthane.'),
    ('seconde-physique-ch5', 'Réactions chimiques et stœchiométrie', 'Ce cours équilibre les réactions chimiques en respectant la conservation des éléments et des charges. Une équation bilan indique les réactifs à gauche et les produits à droite. Les coefficients stœchiométriques assurent l''équilibre. Les quantités de matière n = m/M s''expriment en moles. Le tableau d''avancement suit l''évolution d''une réaction. Applications à la neutralisation acide-base, à la combustion, et à la préparation d''engrais pour les sols togolais.'),
    ('seconde-anglais-ch1', 'Present Simple : Habits and Routines', 'The present simple is used to describe habits, routines, and general truths. Structure : subject + base verb (+s for third person singular). Time expressions : always, usually, often, sometimes, rarely, never. Examples : ''I wake up at 6 AM every day.'' ''She studies mathematics at the lycée.'' ''The Togolese national team plays football on weekends.'' Negative form : subject + do/does + not + base verb. Questions : Do/Does + subject + base verb? Practice with daily schedules of Togolese students.'),
    ('seconde-anglais-ch1', 'Present Continuous : Actions in Progress', 'The present continuous describes actions happening now or around now. Structure : subject + am/is/are + verb-ing. Time expressions : now, at the moment, currently, today. Examples : ''I am reading a physics textbook.'' ''They are discussing the history of Togo.'' ''The teacher is explaining quadratic equations.'' Spelling rules for -ing forms : doubling final consonant, dropping silent -e, changing -ie to -y. Contrast with present simple through situational dialogues.'),
    ('seconde-anglais-ch1', 'Time Expressions and Daily Schedules', 'This lesson expands vocabulary for describing daily life. Morning routines : wake up, brush teeth, have breakfast, go to school. School activities : attend classes, take notes, do homework, study for exams. Evening activities : have dinner, watch TV, read books, go to bed. Prepositions of time : at (6 o''clock), on (Monday), in (the morning). Writing exercise : describe a typical day at a Togolese lycée in 150 words.'),
    ('seconde-anglais-ch2', 'Past Simple : Regular and Irregular Verbs', 'The past simple describes completed actions in the past. Regular verbs : add -ed (walk → walked, study → studied). Irregular verbs must be memorized (go → went, eat → ate, see → saw). Time expressions : yesterday, last week, in 2020, ago. Examples : ''I visited Lomé last summer.'' ''She passed her mathematics exam.'' ''They discovered new historical facts about the Ewe people.'' Negative : subject + did + not + base verb. Questions : Did + subject + base verb?'),
    ('seconde-anglais-ch2', 'Past Continuous : Interrupted Actions', 'The past continuous describes actions in progress at a specific moment in the past. Structure : subject + was/were + verb-ing. Used with the past simple to show interruption : ''While I was studying, my phone rang.'' ''They were playing football when it started raining.'' Time expressions : while, when, as. Narrative tenses : combining past simple for main events and past continuous for background description. Story writing : a memorable day in Togo.'),
    ('seconde-anglais-ch2', 'Narrative Techniques and Storytelling', 'This lesson develops narrative skills. Story structure : exposition (setting, characters), rising action, climax, falling action, resolution. Linking words for time sequence : first, then, next, after that, finally. Descriptive language : adjectives for emotions, adverbs for manner. Dialogue punctuation rules. Reading comprehension : excerpts from Togolese writers in English translation. Creative writing : write a 200-word story about a journey from Sokodé to Lomé.'),
    ('seconde-anglais-ch3', 'Will and Going to for Future', 'Two main ways to express the future. ''Going to'' : plans and intentions (I am going to study medicine). Predictions based on present evidence (Look at those clouds! It is going to rain). ''Will'' : spontaneous decisions (I will help you), promises (I will call you tomorrow), predictions based on opinion (I think it will be sunny). Time expressions : tomorrow, next year, soon, in the future. Practice with career plans of Togolese students.'),
    ('seconde-anglais-ch3', 'Present Continuous for Future Arrangements', 'The present continuous can express definite future plans. Used with a specific time reference : ''I am meeting my friend at 3 PM tomorrow.'' ''We are taking the bus to Kara next weekend.'' Distinction : going to (intention) vs present continuous (fixed arrangement) vs will (spontaneous). Role-plays : making appointments, planning a school trip to the Koutammakou UNESCO site.'),
    ('seconde-anglais-ch3', 'Future Predictions and Debates', 'This lesson practices advanced future forms. Modal verbs for prediction : may, might, could, will probably, is likely to. Debate structures : expressing opinions (In my opinion..., I believe that...), agreeing and disagreeing (I see your point, but...; That''s an interesting perspective). Topics : the future of education in Togo, technology in African schools, climate change effects on Lomé. Group debate preparation and presentation.'),
    ('seconde-anglais-ch4', 'Comparative Adjectives', 'Comparative forms describe differences between two things. Short adjectives : add -er (tall → taller, big → bigger). Long adjectives : use more (beautiful → more beautiful). Irregular : good → better, bad → worse, far → farther/further. Structure : A + be + comparative + than + B. Examples : ''Mathematics is more difficult than English.'' ''Lomé is bigger than Sokodé.'' ''The Togolese coastline is longer than the Beninese one.'' Double comparatives : The more you study, the better your grades.'),
    ('seconde-anglais-ch4', 'Superlative Adjectives', 'Superlative forms describe the extreme quality within a group. Short adjectives : add -est (tall → tallest). Long adjectives : use most (beautiful → most beautiful). Irregular : good → best, bad → worst. Structure : A + be + the + superlative. Examples : ''Kpalimé has the most beautiful mountains in Togo.'' ''This is the most challenging exercise in the book.'' ''She is the best student in our class.'' Practice with descriptions of Togolese geography, culture, and achievements.'),
    ('seconde-anglais-ch4', 'Cultural Comparisons : Togo and the World', 'This lesson applies comparison skills to cultural topics. Comparing educational systems : Togo vs France vs USA vs UK. Comparing traditions : Ewe vs Mina vs Kabiyé customs. Comparing food : fufu vs baguette vs hamburger. Comparing music : Togolese traditional vs hip-hop vs classical. Writing a comparative essay (250 words) : ''Life in a Togolese village vs life in an English-speaking city.'' Use of contrastive linking words : however, whereas, on the other hand, while.'),
    ('seconde-anglais-ch5', 'Zero and First Conditionals', 'Conditional sentences express hypothetical situations. Zero conditional : general truths and scientific facts. If + present simple, present simple. ''If you heat water to 100°C, it boils.'' First conditional : real possibilities in the future. If + present simple, will + base verb. ''If I study hard, I will pass the baccalauréat.'' ''If it rains tomorrow, we will stay home.'' Variations with unless, as long as, provided that. Practice with study strategies and exam preparation.'),
    ('seconde-anglais-ch5', 'Second Conditional : Hypothetical Present', 'The second conditional describes unreal or unlikely situations now or in the future. If + past simple, would + base verb. ''If I were president of Togo, I would improve the education system.'' ''If I had more time, I would learn German.'' Note : ''If I were'' (subjunctive) is formally correct, though ''If I was'' is common in speech. Wish + past simple : ''I wish I knew more about physics.'' Practice with imaginary scenarios.'),
    ('seconde-anglais-ch5', 'Expressing Wishes and Regrets', 'This lesson expands on hypothetical language. Wish + past perfect for regrets about the past : ''I wish I had studied harder last year.'' ''She wishes she had visited the Koutammakou site.'' Regret + -ing / regret + to-infinitive : ''I regret not studying more.'' ''I regret to inform you that...'' If only + past simple/past perfect for stronger emotion. Creative writing : ''A letter to my past self'' with five wishes and regrets.'),
    ('seconde-francais-ch1', 'La structure du récit', 'Ce cours analyse la structure narrative classique. La situation initiale présente le monde ordinaire du personnage principal, son environnement, ses habitudes. L''élément perturbateur est l''événement qui bouleverse cet équilibre : une découverte, un départ, une rencontre, un danger. Les péripéties sont les actions entreprises par le héros pour rétablir l''ordre ou atteindre son objectif. Le dénouement résout l''intrigue, soit de façon heureuse (dénouement comique), soit malheureuse (dénouement tragique). Nous étudions cette structure dans un conte africain et dans un extrait de roman français.'),
    ('seconde-francais-ch1', 'Les types de personnages', 'Ce cours classe les personnages selon leur fonction narrative. Le héros (ou protagoniste) est le personnage central autour duquel s''organise l''intrigue. L''antagoniste s''oppose au héros et crée les obstacles. Les personnages secondaires (figurants, confident, sage) accompagnent, conseillent ou contrarient le héros. Les personnages peuvent être plats (stéréotypés, sans évolution) ou rounds (complexes, en évolution). Nous analysons les personnages d''un roman sénégalais et d''une nouvelle française contemporaine.'),
    ('seconde-francais-ch1', 'Analyse d''un récit africain', 'Ce cours applique les outils narratifs à un conte traditionnel togolais. Étude du récit ''Le Roi et le Python'' : structure en cinq actes, rôle du python comme animal totem, fonction du griot-narrateur. Comparaison avec la structure du roman moderne. Exercice de réécriture : transformer le conte oral en récit écrit avec dialogues et description du décor. Analyse du point de vue narratif : qui raconte ? Quel effet cela produit-il sur le lecteur ?'),
    ('seconde-francais-ch2', 'Le vers et ses caractéristiques', 'Ce cours définit les éléments formels de la poésie. Le vers est une unité de mesure rythmique, délimitée par une coupure (fin de ligne). Le mètre est le nombre de syllabes par vers : alexandrin (12 syllabes), octosyllabe (8), décasyllabe (10). Le rythme est marqué par la césure (pause au milieu du vers) et l''enjambement (phrase qui dépasse le vers). La rime est la répétition de sons en fin de vers : rimes plates (AABB), croisées (ABAB), embrassées (ABBA). Étude de vers classiques français.'),
    ('seconde-francais-ch2', 'Les figures de style essentielles', 'Ce cours inventorie les principales figures de style. La comparaison établit un rapport entre deux réalités à l''aide d''un outil de comparaison (comme, tel, pareil à). La métaphore identifie deux termes sans outil (''Le temps est un voleur''). La personnification donne des traits humains à un objet ou animal. L''hyperbole exagère la réalité (''J''ai mille choses à faire''). Le paradoxe associe deux termes contradictoires (''Une nuit blanche''). Exercices d''identification dans des poèmes de Senghor et Césaire.'),
    ('seconde-francais-ch2', 'Analyse poétique : de Senghor à la négritude', 'Ce cours étudie la poésie de la négritude. Léopold Sédar Senghor et Aimé Césaire réhabilitent la culture africaine face au colonialisme. Thèmes récurrents : la terre natale, les ancêtres, la beauté noire, la révolte. Analyse détaillée du poème ''Femme noire'' de Senghor : structure en strophes, rythme ternaire, images sensuelles, glorification du corps africain. Comparaison avec un poème de Baudelaire sur la beauté. Exercice d''écriture : un poème en hommage à la culture togolaise.'),
    ('seconde-francais-ch3', 'Structure de l''argumentation', 'Ce cours formalise l''art de convaincre. La thèse est la position défendue par l''auteur. Les arguments sont les raisons justifiant cette thèse, appuyées par des exemples précis, des statistiques, des témoignages, des références d''autorité. L''antithèse présente l''opinion contraire pour la réfuter. La synthèse ou conclusion récapitule les arguments et affirme la thèse. Nous analysons la structure d''un éditorial du journal Togolese ''Togo-Presse'' et d''un discours politique français.'),
    ('seconde-francais-ch3', 'Les connecteurs logiques', 'Ce cours classe les connecteurs selon leur fonction argumentative. Addition : de plus, en outre, par ailleurs. Opposition : cependant, néanmoins, toutefois. Cause : en effet, car, parce que. Conséquence : donc, ainsi, par conséquent. But : afin de, pour que. Condition : à condition que, pourvu que. Exemple : par exemple, en particulier. Concession : bien que, quoique, même si. Exercices de réécriture : transformer un texte désorganisé en argumentation cohérente.'),
    ('seconde-francais-ch3', 'Rédaction argumentative appliquée', 'Ce cours pratique la rédaction argumentative. Sujet de dissertation : ''Les réseaux sociaux sont-ils un danger pour la jeunesse togolaise ?'' Plan détaillé : introduction avec définition des termes et annonce de plan, deux parties (thèse et antithèse) avec deux sous-parties chacune, conclusion ouvrant sur une question future. Critères d''évaluation : richesse du vocabulaire, variété des constructions syntaxiques, pertinence des exemples, rigueur logique. Correction collective d''une copie modèle.'),
    ('seconde-francais-ch4', 'Genres dramatiques : comédie et tragédie', 'Ce cours distingue les deux grands genres dramatiques. La comédie provoque le rire par la satire des mœurs, les quiproquos, les personnages ridicules. La tragédie évoque la pitié et la terreur par la chute d''un personnage de haut rang. Les règles classiques : les trois unités (d''action, de lieu, de temps), la vraisemblance, la bienséance. Nous comparons une scène de Molière (Le Misanthrope) avec une scène de Corneille (Le Cid).'),
    ('seconde-francais-ch4', 'Les didascalies et la mise en scène', 'Ce cours étudie les éléments non dialogués du texte théâtral. Les didascalies sont les indications scéniques entre parenthèses ou en italiques : entrées et sorties, mouvements, intonations, décor. Elles ne se disent pas mais se jouent. La mise en scène est l''interprétation du metteur en scène : choix du décor, des costumes, de l''éclairage, de la musique. Exercice pratique : écrire les didascalies d''une scène donnée, puis la jouer en classe.'),
    ('seconde-francais-ch4', 'Théâtre africain contemporain', 'Ce cours découvre le théâtre africain moderne. Wole Soyinka (Nigeria), Sony Labou Tansi (Congo), Koulsy Lamko (Tchad) renouvellent les formes dramatiques. Thèmes : la dictature, la corruption, la tradition vs modernité, l''exil. Analyse d''une scène de ''Le Dernier Survivant de la race humaine'' de Labou Tansi : langage créole, rupture des unités classiques, participation du public. Comparaison avec le théâtre de l''absurde européen (Ionesco, Beckett). Atelier d''écriture : écrire une saynète sur la vie lycéenne à Lomé.'),
    ('seconde-francais-ch5', 'Le subjonctif : emplois principaux', 'Ce cours maîtrise le mode subjonctif. Il s''emploie dans les subordonnées introduites par ''que'' après des verbes ou expressions de volonté (vouloir que, désirer que, exiger que), de nécessité (il faut que, il est nécessaire que), de doute (douter que, il est possible que), et d''émotion (être heureux que, regretter que). Formation : partir du radical de la 3e personne du pluriel de l''indicatif présent et ajouter les terminaisons -e, -es, -e, -ions, -iez, -ent. Exceptions : être, avoir, aller, faire, pouvoir, savoir, vouloir.'),
    ('seconde-francais-ch5', 'Le discours rapporté : style direct et indirect', 'Ce cours transforme les énoncés rapportés. Style direct : citation exacte entre guillemets. ''Il dit : « Je viendrai demain. »'' Style indirect : intégration à la phrase principale sans guillemets. ''Il dit qu''il viendra le lendemain.'' Concordance des temps : si le verbe introducteur est au passé, le temps de la subordonnée recule d''un cran (présent → imparfait, futur → conditionnel présent, passé composé → plus-que-parfait). Concordance des personnes et des adverbes de temps et de lieu.'),
    ('seconde-francais-ch5', 'Exercices de transformation avancés', 'Ce cours pratique la réécriture complexe. Transformation du style direct en style indirect avec verbes introducteurs variés (affirmer, demander, promettre, menacer, conseiller). Questions indirectes : ''Je ne sais pas qui il est.'' ''Elle demande ce que tu veux.'' Style indirect libre : mélange du discours du narrateur et du personnage sans marqueurs explicites. Analyse d''un extrait de ''L''Enfant noir'' de Camara Laye où le style indirect libre crée l''immersion. Dictée préparée et réécriture contrôlée.');
INSERT INTO course_sections (course_id, title, content, order_num) SELECT id, 'Introduction et objectifs', 'Cette section présente les objectifs d''apprentissage du cours. À l''issue de cette leçon, l''élève sera capable de maîtriser les concepts fondamentaux abordés, de résoudre des exercices types, et d''appliquer ces connaissances à des situations concrètes. Un récapitulatif des prérequis est fourni, ainsi qu''une vue d''ensemble du plan du cours.', 1 FROM courses WHERE chapter_id = 'seconde-maths-ch1' AND title = 'Les ensembles de nombres';
INSERT INTO course_sections (course_id, title, content, order_num) SELECT id, 'Développement théorique et exemples', 'Cette section constitue le cœur du cours. Les définitions précises sont suivies de démonstrations rigoureuses ou d''explications détaillées. Des exemples résolus pas à pas illustrent chaque nouveau concept. Des encadrés ''À retenir'' soulignent les formules et propriétés essentielles. Des liens avec d''autres chapitres du programme sont établis pour construire une vision cohérente des savoirs.', 2 FROM courses WHERE chapter_id = 'seconde-maths-ch1' AND title = 'Les ensembles de nombres';
INSERT INTO course_sections (course_id, title, content, order_num) SELECT id, 'Exercices d''application et synthèse', 'Cette section propose des exercices progressifs allant de l''application directe à la résolution de problèmes complexes. Des exercices d''entraînement avec correction détaillée permettent l''auto-évaluation. Un exercice de synthèse fait le lien entre les différentes notions du chapitre. Des problèmes ouverts invitent à la réflexion critique et à la créativité.', 3 FROM courses WHERE chapter_id = 'seconde-maths-ch1' AND title = 'Les ensembles de nombres';
