INSERT INTO course_sections (course_id, title, content, order_num) SELECT id, 'Introduction et objectifs', 'Cette section présente les objectifs d''apprentissage du cours. À l''issue de cette leçon, l''élève sera capable de maîtriser les concepts fondamentaux abordés, de résoudre des exercices types, et d''appliquer ces connaissances à des situations concrètes. Un récapitulatif des prérequis est fourni, ainsi qu''une vue d''ensemble du plan du cours.', 1 FROM courses WHERE chapter_id = 'seconde-anglais-ch3' AND title = 'Future Predictions and Debates';
