INSERT INTO exercises (chapter_id, number, title, question, hint, solution, category) VALUES
    ('seconde-maths-ch1', 1, 'Exercice d''application - Ensembles de nombres et calculs', 'Cet exercice d''application permet de verifier la comprehension des notions fondamentales du chapitre ''Ensembles de nombres et calculs''. Il comprend des questions de cours, des calculs directs, et des demonstrations simples. L''eleve doit etre capable de reproduire les methodes vues en cours sans hesitation.', 'Relire le cours et identifier les definitions cles.', 'Solution detaillee avec etapes intermediaires pour l''exercice d''application du chapitre ''Ensembles de nombres et calculs''.', 'exercice'),
    ('seconde-maths-ch1', 2, 'Exercice de synthese - Ensembles de nombres et calculs', 'Cet exercice de synthese fait le lien entre les differentes notions du chapitre ''Ensembles de nombres et calculs'' et les chapitres precedents. Il exige une mobilisation des competences dans un contexte nouveau. L''eleve doit analyser l''enonce, choisir les outils appropries, et rediger une solution structuree.', 'Faire un schema, identifier les donnees, choisir la methode adaptee.', 'Solution complete avec analyse prealable et verification des resultats pour le chapitre ''Ensembles de nombres et calculs''.', 'exercice'),
    ('seconde-maths-ch1', 3, 'Probleme ouvert - Ensembles de nombres et calculs', 'Ce probleme ouvert du chapitre ''Ensembles de nombres et calculs'' invite l''eleve a la reflexion critique et a la creativite. Plusieurs approches sont possibles. L''objectif est de developper l''autonomie et la capacite a argumenter. Le probleme peut faire appel a des connaissances transversales.', 'Explorer differentes pistes, ne pas chercher la solution immediate.', 'Elements de correction et pistes de reflexion pour le probleme ouvert du chapitre ''Ensembles de nombres et calculs''. Plusieurs solutions sont acceptables.', 'exercice'),
    ('seconde-maths-ch2', 1, 'Exercice d''application - Fonctions numériques', 'Cet exercice d''application permet de verifier la comprehension des notions fondamentales du chapitre ''Fonctions numériques''. Il comprend des questions de cours, des calculs directs, et des demonstrations simples. L''eleve doit etre capable de reproduire les methodes vues en cours sans hesitation.', 'Relire le cours et identifier les definitions cles.', 'Solution detaillee avec etapes intermediaires pour l''exercice d''application du chapitre ''Fonctions numériques''.', 'exercice'),
    ('seconde-maths-ch2', 2, 'Exercice de synthese - Fonctions numériques', 'Cet exercice de synthese fait le lien entre les differentes notions du chapitre ''Fonctions numériques'' et les chapitres precedents. Il exige une mobilisation des competences dans un contexte nouveau. L''eleve doit analyser l''enonce, choisir les outils appropries, et rediger une solution structuree.', 'Faire un schema, identifier les donnees, choisir la methode adaptee.', 'Solution complete avec analyse prealable et verification des resultats pour le chapitre ''Fonctions numériques''.', 'exercice'),
