-- ============================================================
-- FONCTION : duplicate_level_data(source_level, target_level)
-- Duplique toutes les données d'un niveau vers un autre
-- en adaptant les IDs textuels et en générant de nouveaux IDs auto-incrémentés
-- ============================================================

CREATE OR REPLACE FUNCTION duplicate_level_data(p_source_level text, p_target_level text)
RETURNS TABLE(copied_subjects integer, copied_chapters integer, copied_courses integer, copied_sections integer, copied_quiz_groups integer, copied_quiz_questions integer, copied_evaluations integer, copied_exercises integer)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_subject record;
    v_chapter record;
    v_course record;
    v_quiz_group record;
    v_new_course_id integer;
    v_new_quiz_group_id bigint;
    v_subjects_count integer := 0;
    v_chapters_count integer := 0;
    v_courses_count integer := 0;
    v_sections_count integer := 0;
    v_quiz_groups_count integer := 0;
    v_quiz_questions_count integer := 0;
    v_evaluations_count integer := 0;
    v_exercises_count integer := 0;
    v_new_subject_id text;
    v_new_chapter_id text;
BEGIN
    -- 1. DUPLIQUER LES MATIÈRES (subjects)
    FOR v_subject IN 
        SELECT * FROM subjects WHERE level_id = p_source_level
    LOOP
        v_new_subject_id := replace(v_subject.id, p_source_level, p_target_level);

        VALUES (v_new_subject_id, p_target_level, v_subject.name, v_subject.icon, v_subject.color, 0, now(), now())
        ON CONFLICT (id) DO UPDATE SET 
            name = EXCLUDED.name, 
            icon = EXCLUDED.icon, 
            color = EXCLUDED.color,
            updated_at = now();

        v_subjects_count := v_subjects_count + 1;

        -- 2. DUPLIQUER LES CHAPITRES de cette matière
        FOR v_chapter IN 
            SELECT * FROM chapters WHERE subject_id = v_subject.id AND level_id = p_source_level
        LOOP
            v_new_chapter_id := replace(v_chapter.id, p_source_level, p_target_level);

            VALUES (v_new_chapter_id, v_new_subject_id, p_target_level, v_chapter.number, v_chapter.title, v_chapter.description, false, v_chapter.is_locked, now(), now())
            ON CONFLICT (id) DO UPDATE SET
                title = EXCLUDED.title,
                description = EXCLUDED.description,
                updated_at = now();

            v_chapters_count := v_chapters_count + 1;

            -- 3. DUPLIQUER LES COURS de ce chapitre
            FOR v_course IN 
                SELECT * FROM courses WHERE chapter_id = v_chapter.id
            LOOP
                VALUES (v_new_chapter_id, v_course.title, v_course.content, now(), now())
                RETURNING id INTO v_new_course_id;

                v_courses_count := v_courses_count + 1;

                -- 4. DUPLIQUER LES SECTIONS de ce cours
                SELECT v_new_course_id, title, content, order_num, now(), now()
                FROM course_sections WHERE course_id = v_course.id;

                v_sections_count := v_sections_count + (SELECT count(*) FROM course_sections WHERE course_id = v_course.id);
            END LOOP;

            -- 5. DUPLIQUER LES QUIZ GROUPS de ce chapitre
            FOR v_quiz_group IN 
                SELECT * FROM quiz_groups WHERE chapter_id = v_chapter.id
            LOOP
                VALUES (v_new_chapter_id, v_quiz_group.title, v_quiz_group.metadata, now())
                RETURNING id INTO v_new_quiz_group_id;

                v_quiz_groups_count := v_quiz_groups_count + 1;

                -- 6. DUPLIQUER LES QUESTIONS de ce quiz group
                SELECT v_new_quiz_group_id, v_new_chapter_id, order_num, question, options, correct_index_val, explanation, now()
                FROM quiz_questions WHERE quiz_group_id = v_quiz_group.id;

                v_quiz_questions_count := v_quiz_questions_count + (SELECT count(*) FROM quiz_questions WHERE quiz_group_id = v_quiz_group.id);
            END LOOP;

            -- 7. DUPLIQUER LES EXERCICES de ce chapitre
            SELECT v_new_chapter_id, number, title, question, hint, solution, category, now(), now()
            FROM exercises WHERE chapter_id = v_chapter.id;

            v_exercises_count := v_exercises_count + (SELECT count(*) FROM exercises WHERE chapter_id = v_chapter.id);

        END LOOP;

        -- 8. DUPLIQUER LES ÉVALUATIONS de cette matière
        SELECT p_target_level, v_new_subject_id, title, type, year, has_subject, has_solution, 
               replace(subject_url, p_source_level, p_target_level),
               replace(solution_url, p_source_level, p_target_level),
               now(), now()
        FROM evaluations WHERE subject_id = v_subject.id AND level_id = p_source_level;

        v_evaluations_count := v_evaluations_count + (SELECT count(*) FROM evaluations WHERE subject_id = v_subject.id AND level_id = p_source_level);

    END LOOP;

    RETURN QUERY SELECT v_subjects_count, v_chapters_count, v_courses_count, v_sections_count, v_quiz_groups_count, v_quiz_questions_count, v_evaluations_count, v_exercises_count;
END;
$$;



