-- ============================================================

-- Dupliquer Seconde -> Première
SELECT * FROM duplicate_level_data('seconde', 'premiere');

-- Dupliquer Seconde -> Terminale  
SELECT * FROM duplicate_level_data('seconde', 'terminale');



-- ============================================================
-- RÉACTIVATION DES TRIGGERS
-- ============================================================

ALTER TABLE chapters ENABLE TRIGGER on_chapter_created;
ALTER TABLE courses ENABLE TRIGGER trg_notify_new_course;
ALTER TABLE evaluations ENABLE TRIGGER trg_notify_new_evaluation;
ALTER TABLE exercises ENABLE TRIGGER trg_notify_new_exercise;
ALTER TABLE quiz_questions ENABLE TRIGGER trg_sync_quiz_questions_to_legacy;

-- Vérification rapide
SELECT 'Subjects' as table_name, count(*) as count FROM subjects WHERE level_id IN ('seconde', 'premiere', 'terminale')
UNION ALL
SELECT 'Chapters', count(*) FROM chapters WHERE level_id IN ('seconde', 'premiere', 'terminale')
UNION ALL
SELECT 'Courses', count(*) FROM courses WHERE chapter_id LIKE 'seconde-%' OR chapter_id LIKE 'premiere-%' OR chapter_id LIKE 'terminale-%'
UNION ALL
SELECT 'Course Sections', count(*) FROM course_sections
UNION ALL
SELECT 'Quiz Groups', count(*) FROM quiz_groups WHERE chapter_id LIKE 'seconde-%' OR chapter_id LIKE 'premiere-%' OR chapter_id LIKE 'terminale-%'
UNION ALL
SELECT 'Quiz Questions', count(*) FROM quiz_questions WHERE chapter_id LIKE 'seconde-%' OR chapter_id LIKE 'premiere-%' OR chapter_id LIKE 'terminale-%'
UNION ALL
SELECT 'Evaluations', count(*) FROM evaluations WHERE level_id IN ('seconde', 'premiere', 'terminale')
UNION ALL
SELECT 'Exercises', count(*) FROM exercises WHERE chapter_id LIKE 'seconde-%' OR chapter_id LIKE 'premiere-%' OR chapter_id LIKE 'terminale-%'
UNION ALL
SELECT 'Visit Stats', count(*) FROM chapter_visit_stats;